import{_ as a,o as n,c as l,ak as o,ek as p}from"./chunks/framework.DLt_otXO.js";const g=JSON.parse('{"title":"内存机制","description":"","frontmatter":{"title":"内存机制","date":"2022-06-21T22:51:00.000Z","permalink":"/pages/e409ca/","categories":["数据结构和算法","数据结构","栈"],"tags":[null]},"headers":[],"relativePath":"数据结构和算法/数据结构/栈/JS内存机制.md","filePath":"数据结构和算法/数据结构/栈/JS内存机制.md","lastUpdated":1777258973000}'),e={name:"数据结构和算法/数据结构/栈/JS内存机制.md"};function t(r,s,c,i,E,y){return n(),l("div",null,[...s[0]||(s[0]=[o(`<h2 id="_1-简介" tabindex="-1">1. 简介 <a class="header-anchor" href="#_1-简介" aria-label="Permalink to “1. 简介”">​</a></h2><p><code>JavaScript</code> 中的内存空间主要分为三种类型：</p><ul><li><ol><li>代码空间：主要⽤来存放可执⾏代码</li></ol></li><li><ol start="2"><li>栈空间：调⽤栈的存储空间就是栈空间。</li></ol></li><li><ol start="3"><li>堆空间</li></ol></li></ul><p>代码空间主要⽤来存放可执⾏代码的。<code>栈空间</code>及<code>堆空间</code>主要⽤来<code>存放数据</code>的。接下来我们主要介绍栈 空间及堆空间。</p><p>JavaScript 中的变量类型有 8 种，可分为两类：基本类型、引⽤类型</p><ul><li><ol><li>基本类型(值类型)</li></ol><ul><li>string</li><li>number</li><li>undefined</li><li>null</li><li>symbol</li><li>bigint</li></ul></li><li><ol start="2"><li>引用类型</li></ol><ul><li>Object</li></ul></li></ul><p>其中，基本类型是保存在栈内存中的简单数据段，⽽引⽤类型保存在堆内存中。</p><h2 id="_2-栈空间" tabindex="-1">2. 栈空间 <a class="header-anchor" href="#_2-栈空间" aria-label="Permalink to “2. 栈空间”">​</a></h2><p>基本类型在内存中占有<strong>固定⼤⼩的空间</strong>，所以它们的值保存在栈空间，我们通过<strong>按值访问</strong> 。 ⼀般栈空间不会很⼤。</p><h2 id="_3-堆空间" tabindex="-1">3. 堆空间 <a class="header-anchor" href="#_3-堆空间" aria-label="Permalink to “3. 堆空间”">​</a></h2><p>引⽤类型，值⼤⼩不固定，但指向值的<strong>指针⼤⼩</strong>（内存地址）是固定的，所以<strong>把对象放⼊堆中</strong>，将对 象的<strong>地址</strong>放⼊<strong>栈</strong>中，这样，在调⽤栈中切换上下⽂时，只需要将指针下移到上个执⾏上下⽂的地址就 可以了，同时保证了栈空间不会很⼤。</p><p>当查询引⽤类型的变量时， 先从<strong>栈</strong>中<strong>读取内存地址</strong>， 然后再通过地址找到堆中的值。对于这种，我 们把它叫做 <strong>按引⽤访问</strong> 。 ⼀般堆内存空间很⼤，能存放很多数据，但它内存分配与回收都需要花费⼀定的时间。</p><p>举个例⼦帮助理解⼀下：</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">var</span><span style="color:#E1E4E8;"> a </span><span style="color:#F97583;">=</span><span style="color:#79B8FF;"> 1</span><span style="color:#E1E4E8;">;</span></span>
<span class="line"><span style="color:#F97583;">function</span><span style="color:#B392F0;"> foo</span><span style="color:#E1E4E8;">() {</span></span>
<span class="line"><span style="color:#F97583;">  var</span><span style="color:#E1E4E8;"> b </span><span style="color:#F97583;">=</span><span style="color:#79B8FF;"> 2</span><span style="color:#E1E4E8;">;</span></span>
<span class="line"><span style="color:#F97583;">  var</span><span style="color:#E1E4E8;"> c </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> { name: </span><span style="color:#9ECBFF;">&quot;an&quot;</span><span style="color:#E1E4E8;"> };</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span>
<span class="line"><span style="color:#6A737D;">// 函数调⽤</span></span>
<span class="line"><span style="color:#B392F0;">foo</span><span style="color:#E1E4E8;">();</span></span></code></pre></div><img src="`+p+`"><p>基本类型（栈空间）与引⽤类型（堆空间）的存储⽅式决定了：基本类型赋值是<strong>值赋值</strong>，⽽引⽤类型赋值是<strong>地址赋值</strong>。</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#6A737D;">// 值赋值</span></span>
<span class="line"><span style="color:#F97583;">var</span><span style="color:#E1E4E8;"> a </span><span style="color:#F97583;">=</span><span style="color:#79B8FF;"> 1</span></span>
<span class="line"><span style="color:#F97583;">var</span><span style="color:#E1E4E8;"> b </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> a a </span><span style="color:#F97583;">=</span><span style="color:#79B8FF;"> 2</span></span>
<span class="line"><span style="color:#E1E4E8;">console.</span><span style="color:#B392F0;">log</span><span style="color:#E1E4E8;">(b)</span></span>
<span class="line"><span style="color:#6A737D;">// 1</span></span>
<span class="line"><span style="color:#6A737D;">// b 不变</span></span>
<span class="line"><span style="color:#6A737D;">// 地址赋值</span></span>
<span class="line"><span style="color:#F97583;">var</span><span style="color:#E1E4E8;"> a1 </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> {name: </span><span style="color:#9ECBFF;">&#39;an&#39;</span><span style="color:#E1E4E8;">}</span></span>
<span class="line"><span style="color:#F97583;">var</span><span style="color:#E1E4E8;"> b1 </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> a1</span></span>
<span class="line"><span style="color:#E1E4E8;">a1.name </span><span style="color:#F97583;">=</span><span style="color:#9ECBFF;"> &#39;bottle&#39;</span></span>
<span class="line"><span style="color:#E1E4E8;">console.</span><span style="color:#B392F0;">log</span><span style="color:#E1E4E8;">(b1)</span></span>
<span class="line"><span style="color:#6A737D;">// {name: &quot;bottle&quot;}</span></span>
<span class="line"><span style="color:#6A737D;">// b1 值改变</span></span></code></pre></div>`,17)])])}const F=a(e,[["render",t]]);export{g as __pageData,F as default};
